#include<bits/stdc++.h>
using namespace std;
long long die(long long x, long long d) {
	if (x == 0) {
		return 0;
	}
	return 10 * die(x - 1, d) + (d == 0 ? pow(10, x - 1) : x);
}
int main() {
	string s;
	int xx;
	long long ans = 0;
	cin >> s >> xx;
	for (int i = 0; i < s.size(); i++) {
		if (xx == 0) {
			ans += ((s[i] - '0') * die(s.size() - i - 1, 1));
		} else {
			if (s[i] - '0' < xx) ans += ((s[i] - '0') * die(s.size() - i - 1, 0));
			else if (s[i] - '0' > xx)ans += (((s[i] - '0') * die(s.size() - i - 1, 0)) + pow(10, s.size() - i - 1));
			else {
				long long num = 0;
				for (int j = i + 1; j < s.size(); j++)
					num = num * 10 + s[j] - '0';
				ans += (s[i] - '0') * die(s.size() - i - 1, 0) + num + 1;
			}
		}
	}
	cout << ans;
}
